starter:
.image {
  mask-image: linear-gradient(to bottom, black, transparent);
  -webkit-mask-image: /* repeat */;
}

.container { position: relative; }
.container img { position: absolute; }
.container .top {
  mask-image: radial-gradient(circle at center, black 30%, transparent 31%);
  /* Add positioning */
}

.page {
  mask-image: radial-gradient(circle at center, black 0%, black var(--size), transparent calc(var(--size) + 1px));
  animation: reveal 1.5s ease-out forwards;
}
@keyframes reveal {
  from { --size: 0%; }
  to { --size: 100%; }
}
